mapper.update:
MERGE INTO E_MATERIAL_APPLICATION_DETAIL T1 USING (
SELECT #{item.id} AS ID, #{item.purchaseDetailId} AS PURCHASE_DETAIL_ID FROM DUAL
) T2 ON (T1.ID = T2.ID) WHEN MATCHED THEN UPDATE SET T1.PURCHASE_DETAIL_ID = T2.PURCHASE_DETAIL_ID

UPDATE E_MATERIAL_APPLICATION_DETAIL
SET PURCHASE_DETAIL_ID = NULL
WHERE PURCHASE_DETAIL_ID = #{purchaseDetailId}

mapper.select:
SELECT D.ID, D.APPLICATION_ID, D.MATERIAL_CODE_ID, D.MATERIAL_CODE, D.MATERIAL_NAME, D.SPECIFICATION_MODEL, D.UNIT, D.APPLICATION_QUANTITY, D.ESTIMATED_PRICE, D.AMOUNT, D.FLOW_TYPE, D.FLOW_DIRECTION, D.EQUIP_IDS, D.SUPPLY_TIME_LIMIT, D.SUGGESTED_BRAND, D.SPECIFICATION_DESC, D.PURCHASE_DETAIL_ID, A.APPLICATION_NO, A.APPLICATION_TITLE, A.APPLICATION_TYPE_NAME, CASE WHEN c3.CATEGORY_NAME IS NOT NULL AND c2.CATEGORY_NAME IS NOT NULL AND c.CATEGORY_NAME IS NOT NULL THEN c3.CATEGORY_NAME || '/' || c2.CATEGORY_NAME || '/' || c.CATEGORY_NAME WHEN c2.CATEGORY_NAME IS NOT NULL AND c.CATEGORY_NAME IS NOT NULL THEN c2.CATEGORY_NAME || '/' || c.CATEGORY_NAME WHEN c.CATEGORY_NAME IS NOT NULL THEN c.CATEGORY_NAME ELSE '' END AS CATEGORY_NAME, D.CREATE_BY, D.CREATE_BY_NAME, D.CREATE_TIME, D.UPDATE_BY, D.UPDATE_BY_NAME, D.UPDATE_TIME FROM E_MATERIAL_APPLICATION_DETAIL D INNER JOIN E_MATERIAL_APPLICATION A ON D.APPLICATION_ID = A.ID LEFT JOIN E_MATERIAL_CODE MC ON D.MATERIAL_CODE_ID = MC.ID AND MC.DEL_FLAG = 0 LEFT JOIN E_MATERIAL_CATEGORY c ON MC.CATEGORY_ID = c.ID AND c.DEL_FLAG = 0 LEFT JOIN E_MATERIAL_CATEGORY c2 ON c.PARENT_ID = c2.ID AND c2.DEL_FLAG = 0 LEFT JOIN E_MATERIAL_CATEGORY c3 ON c2.PARENT_ID = c3.ID AND c3.DEL_FLAG = 0 LEFT JOIN BPM_BUSINESS_INSTANCE t3 ON t3.BUSINESS_DATA_ID = A.ID
t3.INSTANCE_STATUS='2'
AND A.APPLICATION_NO LIKE #{applicationNoPattern}
AND A.APPLICATION_TITLE LIKE #{applicationTitlePattern}
AND D.MATERIAL_NAME LIKE #{materialNamePattern}
AND D.MATERIAL_CODE LIKE #{materialCodePattern}
AND A.CREATE_TIME >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND A.CREATE_TIME < TO_DATE(#{endDate}, 'YYYY-MM-DD') + 1
AND (D.PURCHASE_DETAIL_ID IS NULL OR D.PURCHASE_DETAIL_ID = '')
AND D.PURCHASE_DETAIL_ID IS NOT NULL AND D.PURCHASE_DETAIL_ID != ''
AND A.FIXED_SERVICE_CATEGORY_CODE = #{fixedServiceCategoryCode}
AND (A.FIXED_SERVICE_CATEGORY_CODE IS NULL OR A.FIXED_SERVICE_CATEGORY_CODE = '')
ORDER BY A.CREATE_TIME DESC, D.CREATE_TIME ASC

SELECT AD.ID AS APPLICATION_DETAIL_ID, PD.ID AS PURCHASE_DETAIL_ID, PD.PURCHASE_ID, AD.MATERIAL_CODE, AD.MATERIAL_CODE_ID AS MATERIAL_ID, AD.MATERIAL_NAME, P.SUPPLIER_NAME, NVL(MC.SPECIFICATION_MODEL, AD.SPECIFICATION_MODEL) AS SPECIFICATION_MODEL, AD.SUGGESTED_BRAND, MC.BRAND AS brand, AD.APPLICATION_QUANTITY, PD.TAX_INCLUDED_UNIT_PRICE, PD.TAX_INCLUDED_AMOUNT, PD.TAX_RATE, AD.UNIT, AD.SUPPLY_TIME_LIMIT, AD.FLOW_TYPE, AD.FLOW_DIRECTION, AD.EQUIP_IDS, AD.SPECIFICATION_DESC, PD.PURCHASE_QUANTITY, NVL(SUM_WID.WAREHOUSE_IN_QUANTITY, 0) AS WAREHOUSE_IN_QUANTITY, (PD.PURCHASE_QUANTITY - NVL(SUM_WID.WAREHOUSE_IN_QUANTITY, 0)) AS REMAINING_QUANTITY, A.APPLICATION_NO, A.APPLICATION_TITLE, A.APPLICATION_TYPE_NAME, A.DEPT_ID AS APPLICATION_DEPT_ID, A.DEPT_NAME AS APPLICATION_DEPT_NAME, P.SUPPLIER_ID, P.CREATE_BY AS PURCHASE_CREATE_BY, P.CREATE_BY_NAME AS PURCHASE_CREATE_BY_NAME, P.PURCHASE_NO, P.PURCHASE_TYPE_NAME, P.FIXED_SERVICE_CATEGORY_NAME FROM E_MATERIAL_PURCHASE_DETAIL PD INNER JOIN E_MATERIAL_PURCHASE P ON PD.PURCHASE_ID = P.ID LEFT JOIN E_MATERIAL_APPLICATION_DETAIL AD ON PD.ID = AD.PURCHASE_DETAIL_ID LEFT JOIN E_MATERIAL_APPLICATION A ON AD.APPLICATION_ID = A.ID LEFT JOIN E_MATERIAL_CODE MC ON AD.MATERIAL_CODE_ID = MC.ID AND MC.DEL_FLAG = 0 LEFT JOIN BPM_BUSINESS_INSTANCE t3 ON t3.BUSINESS_DATA_ID = P.ID LEFT JOIN ( SELECT AD_INNER.PURCHASE_DETAIL_ID, SUM(WID.WAREHOUSE_IN_QUANTITY) AS WAREHOUSE_IN_QUANTITY FROM E_MATERIAL_WAREHOUSE_IN_DETAIL WID INNER JOIN E_MATERIAL_APPLICATION_DETAIL AD_INNER ON WID.APPLICATION_ID = AD_INNER.ID WHERE WID.APPLICATION_ID IS NOT NULL AND AD_INNER.PURCHASE_DETAIL_ID IS NOT NULL GROUP BY AD_INNER.PURCHASE_DETAIL_ID ) SUM_WID ON PD.ID = SUM_WID.PURCHASE_DETAIL_ID
t3.INSTANCE_STATUS = 2 AND (PD.PURCHASE_QUANTITY - NVL(SUM_WID.WAREHOUSE_IN_QUANTITY, 0)) > 0
AND A.APPLICATION_NO LIKE #{applicationNoPattern}
AND P.PURCHASE_NO LIKE #{purchaseNoPattern}
AND AD.MATERIAL_NAME LIKE #{materialNamePattern}
AND P.SUPPLIER_NAME LIKE #{supplierNamePattern}
AND P.SUPPLIER_ID = #{supplierId}
ORDER BY P.CREATE_TIME DESC, PD.CREATE_TIME ASC

SELECT SPECIFICATION_DESC
FROM E_MATERIAL_APPLICATION_DETAIL
WHERE ID = #{id}
